if (!args.resume_from_qemu.empty())
  sim.apply_resume_from_qemu(args.resume_from_qemu);

if (args.hybrid_enter_pc)
  spdlog::warn("--hybrid-enter-pc=0x{:x} ignored: entry trigger is "
               "QEMU's job (use plugin enter_pc= arg)",
               *args.hybrid_enter_pc);

if (!args.handoff_out.empty()) {
  if (args.hybrid_icount && args.hybrid_exit_pc)
    throw std::runtime_error(
      "--hybrid-icount and --hybrid-exit-pc are mutually exclusive");
  if (args.hybrid_icount)
    sim.enable_hybrid_icount_handoff(args.handoff_out,
                                     *args.hybrid_icount);
  else if (args.hybrid_exit_pc)
    sim.enable_hybrid_handoff(args.elf_file, args.handoff_out,
                              *args.hybrid_exit_pc);
  else
    sim.enable_hybrid_handoff(args.elf_file, args.handoff_out);
}

const int exit_code = sim.run();

sim.cpu.final();

if (exit_code == hybrid::kExitHandoffToQemu && !args.qemu_binary.empty()) {
  hybrid_state_v1 state{};
  std::ifstream sf(args.handoff_out, std::ios::binary);
  if (!sf)
    throw std::runtime_error("handoff: cannot read drained state file: "
                             + args.handoff_out);
  sf.read(reinterpret_cast<char*>(&state), sizeof(state));
  if (!sf)
    throw std::runtime_error("handoff: short read of drained state file");
  return hybrid::run_qemu_handback(args.qemu_binary, args.elf_file, state,
                                   args.shared_mem_path,
                                   args.shared_mem_size);
}

