/* Tier-2 C-level round-trip smoke test.
 *
 * Phase 1 (QEMU1): printf via newlib stdio -> libgloss_vh -> semihosting,
 *   handled by QEMU. Then csrwi 0x7C0, 0 -- plugin drains state.
 * Phase 2 (vsim):  empty body. Phase-2 rule (rt_c_helpers.h): no syscall
 *   may issue inside this span.
 * Phase 3 (QEMU2): printf again, then crt0 calls _exit(0) -> libgloss_vh
 *   semihosting SYS_EXIT_EXTENDED.
 */

#include "runtime/rt_c_helpers.h"
#include <stdio.h>

int main(void)
{
  printf("hello from QEMU1\n");
  fflush(stdout);

  enter_vsim();
  /* Phase 2: vsim. No syscalls. */
  exit_vsim();

  printf("hello from QEMU2\n");
  fflush(stdout);
  return 0;
}
